.photo-row {
  display: flex;
  padding: 60px 0;
  margin-left: -20px;
  animation: scroll-photos 40s linear infinite;
}

.photo-row img {
  width: 320px;
  height: 360px;
  margin: 0 -15px;
  background: #ffffff;
  padding: 14px 14px 64px 14px;
  border-radius: 6px;
  border: 1px solid rgba(28,27,26,0.04);
  box-shadow: 0 6px 20px rgba(0,0,0,0.06);
  object-fit: cover;
  flex-shrink: 0;
  cursor: pointer;
  transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.photo-row img:nth-child(odd) { transform: rotate(-3deg); }
.photo-row img:nth-child(even) { transform: rotate(4deg) translateY(10px); }
.photo-row img:nth-child(3n) { transform: rotate(-5deg) translateY(-8px); }
.photo-row img:nth-child(5n) { transform: rotate(2deg) translateY(5px); }

.photo-row img:hover {
  transform: scale(1.1) rotate(0deg) translateY(-10px);
  z-index: 10;
  position: relative;
  box-shadow: 0 20px 40px rgba(0,0,0,0.15);
}

@keyframes scroll-photos {
  0% { transform: translateX(0); }
  100% { transform: translateX(calc(-290px * 7)); }
}

/* ============================================
   THREE PRODUCTS
   ============================================ */
.products { padding: 120px 0; }

.section-label {
  font-family: var(--font-display);
  font-size: 13px;
  color: var(--accent);
  letter-spacing: 2px;
  text-transform: uppercase;
  margin-bottom: 16px;
}

.section-title {
  font-size: clamp(36px, 5vw, 56px);
  font-weight: 700;
  letter-spacing: -1.5px;
  margin-bottom: 16px;
  line-height: 1.1;
}

.section-sub {
  font-size: 18px;
  color: var(--gray);
  max-width: 600px;
  margin-bottom: 64px;
  font-weight: 300;
}

.product-cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 24px;
}

