.nav-cta {
  background: var(--accent); color: #ffffff !important;
  padding: 10px 24px; border-radius: 6px;
  font-weight: 600; font-size: 14px; transition: background 0.2s;
}
.nav-cta:hover { background: var(--accent-glow) !important; }

/* HERO */
.hero {
  padding-top: 160px; padding-bottom: 80px;
}
.hero-label {
  font-family: var(--font-display); font-size: 13px;
  color: var(--accent); letter-spacing: 2px; text-transform: uppercase;
  margin-bottom: 24px; display: flex; align-items: center; gap: 12px;
}
.hero-label::before { content: ''; width: 40px; height: 1px; background: var(--accent); }
.hero h1 {
  font-size: clamp(40px, 6vw, 64px); font-weight: 700;
  line-height: 1.05; letter-spacing: -2px; margin-bottom: 20px;
}
.hero h1 em { font-style: normal; color: var(--accent); }
.hero-sub { font-size: 18px; color: var(--gray); max-width: 520px; line-height: 1.6; font-weight: 300; }

/* CONTACT LAYOUT */
.contact-layout {
  display: grid; grid-template-columns: 1fr 1.6fr;
  gap: 80px; align-items: start;
  padding-top: 0; padding-bottom: 120px;
}

/* SIDEBAR */
.contact-sidebar {}
.contact-info-block { margin-bottom: 40px; }
.contact-info-label {
  font-family: var(--font-display); font-size: 11px;
  color: var(--gray); letter-spacing: 1.5px; text-transform: uppercase;
  margin-bottom: 8px;
}
.contact-info-value { font-size: 16px; color: var(--text); font-weight: 500; }
.contact-info-value a { color: var(--accent); }
.contact-info-value a:hover { text-decoration: underline; }

.response-note {
  background: var(--cream); border-radius: 12px; padding: 20px 24px;
  margin-top: 40px;
}
.response-note p { font-size: 14px; color: var(--gray); line-height: 1.6; }
.response-note strong { color: var(--text); }

/* FORM */
.form-card {
  background: #ffffff; border: 1px solid rgba(28,27,26,0.08);
  border-radius: 20px; padding: 48px;
  box-shadow: 0 2px 12px rgba(28,27,26,0.06);
}

.form-group { margin-bottom: 24px; }
.form-group label {
  display: block; font-size: 14px; font-weight: 500;
  color: var(--text); margin-bottom: 8px;
}
.form-group label span { color: var(--accent); }

.form-group input,
.form-group select,
.form-group textarea {
  width: 100%;
  padding: 14px 16px;
  font-family: var(--font-body);
  font-size: 15px;
  color: var(--text);

