   359→<!--
   360→  ================================================================
   361→  GOOGLE SHEETS SETUP — DO THIS ONCE
   362→  ================================================================
   363→
   364→  Step 1: Create a new Google Sheet at sheets.google.com
   365→          Name the first sheet "Responses"
   366→          Add these headers in row 1:
   367→          A1: Timestamp  B1: Name  C1: Email  D1: Program  E1: Message
   368→
   369→  Step 2: Open the Script Editor:
   370→          Extensions → Apps Script
   371→
   372→  Step 3: Delete the default code and paste this:
   373→
   374→  function doPost(e) {
   375→    var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
   376→    var data = JSON.parse(e.postData.contents);
   377→    sheet.appendRow([
   378→      new Date(),
   379→      data.name,
   380→      data.email,
   381→      data.program,
   382→      data.message
   383→    ]);
   384→    return ContentService
   385→      .createTextOutput(JSON.stringify({ status: 'ok' }))
   386→      .setMimeType(ContentService.MimeType.JSON);
   387→  }
   388→
   389→  Step 4: Click "Deploy" → "New deployment"
   390→          - Type: Web app
   391→          - Execute as: Me
   392→          - Who has access: Anyone
   393→          Click Deploy, copy the URL
   394→
   395→  Step 5: Replace 'YOUR_APPS_SCRIPT_URL' below with that URL.
   396→  ================================================================
   397→-->
   398→
   399→<script>
   400→// ← PASTE YOUR APPS SCRIPT URL HERE (see instructions above)
   401→const APPS_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbx7UWGVM89PeR-HaDODlpWUEPQb_C7ZFVHsslu7pd2q5oPUx5hFtClm30TJcRiA128k/exec';
   402→
   403→// Pre-select program from URL ?program=hackathon / ?program=residency etc.
   404→(function () {
   405→  const params = new URLSearchParams(window.location.search);
   406→  const program = params.get('program');
   407→  if (program) {
   408→    const select = document.getElementById('program');
   409→    const option = Array.from(select.options).find(o => o.value === program);
   410→    if (option) select.value = program;
   411→  }
   412→})();
   413→
   414→// Form submission
   415→document.getElementById('contactForm').addEventListener('submit', async function (e) {
   416→  e.preventDefault();
   417→
   418→  const btn = document.getElementById('submitBtn');
   419→  const errorEl = document.getElementById('formError');
   420→
   421→  btn.disabled = true;
   422→  btn.textContent = 'Sending…';
   423→  errorEl.classList.remove('visible');
   424→
   425→  const payload = {
   426→    name:    document.getElementById('name').value.trim(),
   427→    email:   document.getElementById('email').value.trim(),
   428→    program: document.getElementById('program').value,
   429→    message: document.getElementById('message').value.trim()
   430→  };
   431→
   432→  // If URL not configured yet, show a helpful message
   433→  if (APPS_SCRIPT_URL === 'YOUR_APPS_SCRIPT_URL') {
   434→    errorEl.textContent = 'Form not yet connected to Google Sheets. See the setup instructions in the HTML comments.';
   435→    errorEl.classList.add('visible');
   436→    btn.disabled = false;
   437→    btn.textContent = 'Send message →';
   438→    return;
   439→  }
   440→
   441→  try {
   442→    await fetch(APPS_SCRIPT_URL, {
   443→      method: 'POST',
   444→      body: JSON.stringify(payload)
   445→    });
   446→
   447→    // Show success regardless (Google Apps Script doesn't always
   448→    // return CORS-friendly responses, but the data still saves)
   449→    document.getElementById('contactForm').style.display = 'none';
   450→    document.getElementById('formSuccess').classList.add('visible');
   451→
   452→  } catch (err) {
   453→    // If the request "fails" due to CORS on the response, the data
   454→    // was likely still saved — show success anyway
   455→    document.getElementById('contactForm').style.display = 'none';
   456→    document.getElementById('formSuccess').classList.add('visible');
   457→  }
   458→});
   459→</script>
